body:
The `LowerLayers` pass is not updating `hw.hierpath` ops when it creates new modules for layer blocks. Consider:

```
firrtl.circuit "Foo" {
  hw.hierpath private @nla1 [@Foo::@bar]
  hw.hierpath private @nla2 [@Foo::@baz]
  firrtl.layer @A  bind {}
  firrtl.module @Bar() attributes {convention = #firrtl<convention scalarized>} {}
  firrtl.module @Foo() attributes {convention = #firrtl<convention scalarized>} {
    firrtl.layerblock @A {
      firrtl.instance bar sym @bar @Bar()
      firrtl.wire sym @baz : !firrtl.uint<1>
    }
  }
}
```

When compiled with `circt-opt Foo.mlir -firrtl-lower-layers -mlir-print-ir-after-all` this errors out:

```
/Users/schuylereldridge/repos/github.com/seldridge/firrtl-snippets/circt/6717.mlir:2:3: error: 'hw.hierpath' op  operation with symbol: #hw.innerNameRef<@Foo::@bar> was not found 
  hw.hierpath private @nla1 [@Foo::@bar]
  ^
/Users/schuylereldridge/repos/github.com/seldridge/firrtl-snippets/circt/6717.mlir:2:3: note: see current operation: "hw.hierpath"() {namepath = [#hw.innerNameRef<@Foo::@bar>], sym_name = "nla1", sym_visibility = "private"} : () -> ()
/Users/schuylereldridge/repos/github.com/seldridge/firrtl-snippets/circt/6717.mlir:3:3: error: 'hw.hierpath' op  operation with symbol: #hw.innerNameRef<@Foo::@baz> was not found 
  hw.hierpath private @nla2 [@Foo::@baz]
  ^
/Users/schuylereldridge/repos/github.com/seldridge/firrtl-snippets/circt/6717.mlir:3:3: note: see current operation: "hw.hierpath"() {namepath = [#hw.innerNameRef<@Foo::@baz>], sym_name = "nla2", sym_visibility = "private"} : () -> ()
// -----// IR Dump After LowerLayers Failed (firrtl-lower-layers) //----- //
"firrtl.circuit"() ({
  "sv.verbatim"() {format_string = "`ifndef layers_Foo_A\0A`define layers_Foo_A", output_file = #hw.output_file<"layers_Foo_A.sv", excludeFromFileList>, symbols = []} : () -> ()
  "hw.hierpath"() {namepath = [#hw.innerNameRef<@Foo::@bar>], sym_name = "nla1", sym_visibility = "private"} : () -> ()
  "hw.hierpath"() {namepath = [#hw.innerNameRef<@Foo::@baz>], sym_name = "nla2", sym_visibility = "private"} : () -> ()
  "firrtl.module"() ({
  ^bb0:
  }) {annotations = [], convention = #firrtl<convention scalarized>, layers = [], parameters = [], portAnnotations = [], portDirections = 0 : i0, portLocations = [], portNames = [], portSyms = [], portTypes = [], sym_name = "Bar"} : () -> ()
  "firrtl.module"() ({
    "firrtl.instance"() {annotations = [], inner_sym = #hw<innerSym@bar>, layers = [], moduleName = @Bar, name = "bar", nameKind = #firrtl<name_kind droppable_name>, portAnnotations = [], portDirections = 0 : i0, portNames = []} : () -> ()
    %0 = "firrtl.wire"() {annotations = [], inner_sym = #hw<innerSym@baz>, name = "", nameKind = #firrtl<name_kind droppable_name>} : () -> !firrtl.uint<1>
  }) {annotations = [], convention = #firrtl<convention internal>, layers = [], portAnnotations = [], portDirections = 0 : i0, portLocations = [], portNames = [], portSyms = [], portTypes = [], sym_name = "Foo_A", sym_visibility = "private"} : () -> ()
  "firrtl.module"() ({
    "firrtl.instance"() {annotations = [], layers = [], lowerToBind, moduleName = @Foo_A, name = "foo_A", nameKind = #firrtl<name_kind droppable_name>, output_file = #hw.output_file<"layers_Foo_A.sv", excludeFromFileList>, portAnnotations = [], portDirections = 0 : i0, portNames = []} : () -> ()
  }) {annotations = [], convention = #firrtl<convention scalarized>, layers = [], parameters = [], portAnnotations = [], portDirections = 0 : i0, portLocations = [], portNames = [], portSyms = [], portTypes = [], sym_name = "Foo"} : () -> ()
  "sv.verbatim"() {format_string = "`endif // layers_Foo_A", output_file = #hw.output_file<"layers_Foo_A.sv", excludeFromFileList>, symbols = []} : () -> ()
}) {annotations = [], name = "Foo"} : () -> ()
```
